import os
import json
import time
import threading
from datetime import datetime
from collections import defaultdict, Counter
from flask import Flask, request, jsonify
import numpy as np
from PIL import Image
import io
import base64

app = Flask(__name__)

class CrowdsourcedLabelingSystem:
    def __init__(self):
        self.images = {}
        self.annotations = defaultdict(list)
        self.aggregated_labels = {}
        self.model = None
        self.lock = threading.Lock()
        
    def add_image(self, image_id, image_data, image_path=None):
        with self.lock:
            self.images[image_id] = {
                'image_data': image_data,
                'image_path': image_path,
                'upload_time': datetime.now().isoformat(),
                'status': 'pending'
            }
        return True
    
    def add_annotation(self, image_id, annotator_id, label, confidence=1.0):
        if image_id not in self.images:
            return False
        
        with self.lock:
            annotation = {
                'annotator_id': annotator_id,
                'label': label,
                'confidence': confidence,
                'timestamp': datetime.now().isoformat()
            }
            self.annotations[image_id].append(annotation)
        return True
    
    def aggregate_labels_majority_voting(self, min_annotations=3):
        with self.lock:
            for image_id, annots in self.annotations.items():
                if len(annots) >= min_annotations:
                    labels = [a['label'] for a in annots]
                    label_counts = Counter(labels)
                    majority_label = label_counts.most_common(1)[0][0]
                    confidence = label_counts[majority_label] / len(labels)
                    
                    self.aggregated_labels[image_id] = {
                        'label': majority_label,
                        'confidence': confidence,
                        'num_annotations': len(labels),
                        'label_distribution': dict(label_counts)
                    }
                    self.images[image_id]['status'] = 'labeled'
        return len(self.aggregated_labels)
    
    def get_labeled_data(self):
        labeled_data = []
        with self.lock:
            for image_id, label_info in self.aggregated_labels.items():
                if image_id in self.images:
                    labeled_data.append({
                        'image_id': image_id,
                        'image_data': self.images[image_id]['image_data'],
                        'label': label_info['label'],
                        'confidence': label_info['confidence']
                    })
        return labeled_data
    
    def train_model(self):
        labeled_data = self.get_labeled_data()
        
        if len(labeled_data) == 0:
            return {'status': 'error', 'message': 'No labeled data available'}
        
        X = []
        y = []
        
        for item in labeled_data:
            image_data = item['image_data']
            if isinstance(image_data, str):
                try:
                    image_bytes = base64.b64decode(image_data)
                    img = Image.open(io.BytesIO(image_bytes))
                except:
                    continue
            else:
                continue
            
            img = img.convert('RGB')
            img_resized = img.resize((32, 32))
            img_array = np.array(img_resized).flatten()
            
            X.append(img_array)
            y.append(item['label'])
        
        X = np.array(X)
        y = np.array(y)
        
        unique_labels = np.unique(y)
        label_to_idx = {label: idx for idx, label in enumerate(unique_labels)}
        y_encoded = np.array([label_to_idx[label] for label in y])
        
        self.model = SimpleNeuralNetwork(X.shape[1], len(unique_labels))
        self.model.train(X, y_encoded, epochs=50, learning_rate=0.01)
        
        return {
            'status': 'success',
            'num_samples': len(X),
            'num_classes': len(unique_labels),
            'classes': list(unique_labels)
        }
    
    def predict(self, image_data):
        if self.model is None:
            return None
        
        if isinstance(image_data, str):
            try:
                image_bytes = base64.b64decode(image_data)
                img = Image.open(io.BytesIO(image_bytes))
            except:
                return None
        else:
            return None
        
        img = img.convert('RGB')
        img_resized = img.resize((32, 32))
        img_array = np.array(img_resized).flatten()
        
        prediction = self.model.predict(img_array.reshape(1, -1))
        return prediction[0]


class SimpleNeuralNetwork:
    def __init__(self, input_size, num_classes):
        self.input_size = input_size
        self.num_classes = num_classes
        self.hidden_size = 64
        
        self.W1 = np.random.randn(input_size, self.hidden_size) * 0.01
        self.b1 = np.zeros((1, self.hidden_size))
        self.W2 = np.random.randn(self.hidden_size, num_classes) * 0.01
        self.b2 = np.zeros((1, num_classes))
    
    def relu(self, x):
        return np.maximum(0, x)
    
    def softmax(self, x):
        exp_x = np.exp(x - np.max(x, axis=1, keepdims=True))
        return exp_x / np.sum(exp_x, axis=1, keepdims=True)
    
    def forward(self, X):
        self.z1 = np.dot(X, self.W1) + self.b1
        self.a1 = self.relu(self.z1)
        self.z2 = np.dot(self.a1, self.W2) + self.b2
        self.a2 = self.softmax(self.z2)
        return self.a2
    
    def train(self, X, y, epochs=50, learning_rate=0.01):
        m = X.shape[0]
        
        for epoch in range(epochs):
            output = self.forward(X)
            
            y_one_hot = np.zeros((m, self.num_classes))
            y_one_hot[np.arange(m), y] = 1
            
            dz2 = output - y_one_hot
            dW2 = np.dot(self.a1.T, dz2) / m
            db2 = np.sum(dz2, axis=0, keepdims=True) / m
            
            da1 = np.dot(dz2, self.W2.T)
            dz1 = da1 * (self.z1 > 0)
            dW1 = np.dot(X.T, dz1) / m
            db1 = np.sum(dz1, axis=0, keepdims=True) / m
            
            self.W2 -= learning_rate * dW2
            self.b2 -= learning_rate * db2
            self.W1 -= learning_rate * dW1
            self.b1 -= learning_rate * db1
    
    def predict(self, X):
        output = self.forward(X)
        return np.argmax(output, axis=1)


labeling_system = CrowdsourcedLabelingSystem()


@app.route('/upload_image', methods=['POST'])
def upload_image():
    data = request.json
    image_id = data.get('image_id')
    image_data = data.get('image_data')
    
    if not image_id or not image_data:
        return jsonify({'status': 'error', 'message': 'Missing image_id or image_data'}), 400
    
    success = labeling_system.add_image(image_id, image_data)
    
    if success:
        return jsonify({'status': 'success', 'image_id': image_id}), 200
    else:
        return jsonify({'status': 'error', 'message': 'Failed to upload image'}), 500


@app.route('/annotate', methods=['POST'])
def annotate():
    data = request.json
    image_id = data.get('image_id')
    annotator_id = data.get('annotator_id')
    label = data.get('label')
    confidence = data.get('confidence', 1.0)
    
    if not image_id or not annotator_id or label is None:
        return jsonify({'status': 'error', 'message': 'Missing required fields'}), 400
    
    success = labeling_system.add_annotation(image_id, annotator_id, label, confidence)
    
    if success:
        return jsonify({'status': 'success', 'image_id': image_id, 'annotator_id': annotator_id}), 200
    else:
        return jsonify({'status': 'error', 'message': 'Image not found'}), 404


@app.route('/aggregate', methods=['POST'])
def aggregate():
    data = request.json
    min_annotations = data.get('min_annotations', 3)
    
    num_aggregated = labeling_system.aggregate_labels_majority_voting(min_annotations)
    
    return jsonify({
        'status': 'success',
        'num_aggregated': num_aggregated
    }), 200


@app.route('/train', methods=['POST'])
def train():
    result = labeling_system.train_model()
    
    if result['status'] == 'success':
        return jsonify(result), 200
    else:
        return jsonify(result), 400


@app.route('/predict', methods=['POST'])
def predict():
    data = request.json
    image_data = data.get('image_data')
    
    if not image_data:
        return jsonify({'status': 'error', 'message': 'Missing image_data'}), 400
    
    prediction = labeling_system.predict(image_data)
    
    if prediction is not None:
        return jsonify({'status': 'success', 'prediction': int(prediction)}), 200
    else:
        return jsonify({'status': 'error', 'message': 'Prediction failed or model not trained'}), 400


@app.route('/stats', methods=['GET'])
def stats():
    with labeling_system.lock:
        total_images = len(labeling_system.images)
        total_annotations = sum(len(annots) for annots in labeling_system.annotations.values())
        labeled_images = len(labeling_system.aggregated_labels)
        pending_images = total_images - labeled_images
    
    return jsonify({
        'total_images': total_images,
        'total_annotations': total_annotations,
        'labeled_images': labeled_images,
        'pending_images': pending_images
    }), 200


@app.route('/get_labels', methods=['GET'])
def get_labels():
    with labeling_system.lock:
        labels = dict(labeling_system.aggregated_labels)
    
    return jsonify({'labels': labels}), 200


@app.route('/get_image_annotations/<image_id>', methods=['GET'])
def get_image_annotations(image_id):
    with labeling_system.lock:
        if image_id in labeling_system.annotations:
            annotations = labeling_system.annotations[image_id]
            return jsonify({'image_id': image_id, 'annotations': annotations}), 200
        else:
            return jsonify({'status': 'error', 'message': 'Image not found'}), 404


